CREATE OR REPLACE FUNCTION public.answer_question_atomic(p_question_id uuid, p_answer text, p_admin_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_product_name text;
    v_product_id uuid;
BEGIN
    -- SECURITY CHECK: Reject any caller that is not an admin
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Unauthorized: Only admins can answer questions.';
    END IF;

    -- 1. Insert Answer
    INSERT INTO public.answers (question_id, user_id, answer)
    VALUES (p_question_id, p_admin_id, p_answer);

    -- 2. Get Question Info
    SELECT user_id, product_id INTO v_user_id, v_product_id 
    FROM public.questions WHERE id = p_question_id;

    IF v_product_id IS NOT NULL THEN
        SELECT nome INTO v_product_name FROM public.produtos WHERE id = v_product_id;

        -- 3. Log Notification
        INSERT INTO public.push_notifications_log (title, body, url, recipient_count, created_by)
        VALUES (
            'Sua pergunta foi respondida!', 
            'A loja respondeu a sua pergunta sobre o produto ' || COALESCE(v_product_name, 'selecionado') || '.', 
            '/product/' || v_product_id, 
            1, 
            p_admin_id
        );
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.answer_question_atomic(p_question_id uuid, p_answer text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_product_name text;
    v_product_id uuid;
    v_admin_id uuid;
BEGIN
    -- SECURITY CHECK: Ensure the caller is an admin
    v_admin_id := auth.uid();
    IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = v_admin_id AND role = 'admin') THEN
        RAISE EXCEPTION 'Unauthorized: Only admins can answer questions.';
    END IF;

    -- 1. Insert Answer
    INSERT INTO answers (question_id, user_id, answer)
    VALUES (p_question_id, v_admin_id, p_answer);

    -- 2. Get Question Info
    SELECT user_id, product_id INTO v_user_id, v_product_id 
    FROM questions WHERE id = p_question_id;

    IF v_product_id IS NOT NULL THEN
        SELECT nome INTO v_product_name FROM produtos WHERE id = v_product_id;

        -- 3. Log Notification
        INSERT INTO push_notifications_log (title, body, url, recipient_count, created_by)
        VALUES (
            'Sua pergunta foi respondida!', 
            'A loja respondeu à sua pergunta sobre o produto ' || COALESCE(v_product_name, 'selecionado') || '.', 
            '/product/' || v_product_id, 
            1, 
            v_admin_id
        );
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.check_stock_v1(p_product_id uuid, p_variant_id uuid, p_quantity integer)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_stock INTEGER;
BEGIN
    IF p_variant_id IS NOT NULL THEN
        SELECT stock INTO v_stock FROM product_variants WHERE id = p_variant_id AND product_id = p_product_id;
    ELSE
        SELECT stock INTO v_stock FROM produtos WHERE id = p_product_id;
    END IF;

    RETURN COALESCE(v_stock, 0) >= p_quantity;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_marketplace_order(p_items jsonb, p_payment_method text, p_address_id uuid, p_coupon_code text DEFAULT NULL::text, p_customer_name text DEFAULT NULL::text, p_customer_phone text DEFAULT NULL::text, p_observation text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_id uuid := auth.uid();
    v_order_id uuid;
    v_item jsonb;
    v_product_id uuid;
    v_variant_id uuid;
    v_quantity integer;
    v_db_price numeric;
    v_db_stock integer;
    v_calculated_subtotal numeric := 0;
    v_calculated_total numeric := 0;
    v_shipping_validated numeric := 0;
    v_discount_amount numeric := 0;
    v_coupon_id uuid;
    v_store_config RECORD;
    v_product_name text;
    v_image_url text;
BEGIN
    -- [SECURITY] Auth check
    IF v_user_id IS NULL THEN RAISE EXCEPTION 'Não autenticado.'; END IF;

    -- [SECURITY] Address BOLA check
    IF p_address_id IS NOT NULL THEN
        IF NOT EXISTS (SELECT 1 FROM user_addresses WHERE id = p_address_id AND user_id = v_user_id) THEN
            RAISE EXCEPTION 'Endereço inválido ou tentativa de BOLA detectada.';
        END IF;
    END IF;

    -- 1. Load Store Config
    SELECT * INTO v_store_config FROM public.store_config WHERE id = 1;

    -- 2. Validate Items & Calculate Subtotal
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_product_id := (v_item->>'product_id')::uuid;
        v_variant_id := (v_item->>'variant_id')::uuid;
        v_quantity := (v_item->>'quantity')::integer;

        IF v_quantity <= 0 THEN RAISE EXCEPTION 'Quantidade inválida.'; END IF;

        IF v_variant_id IS NOT NULL THEN
            SELECT 
                COALESCE(v.price_override, p.preco_venda), v.stock_increment, p.nome, p.imagem_url
            INTO v_db_price, v_db_stock, v_product_name, v_image_url
            FROM public.produtos p
            JOIN public.product_variants v ON v.product_id = p.id
            WHERE v.id = v_variant_id AND p.id = v_product_id
              AND v.active = true AND p.ativo = true
            FOR NO KEY UPDATE OF v;
        ELSE
            SELECT preco_venda, estoque, nome, imagem_url
            INTO v_db_price, v_db_stock, v_product_name, v_image_url
            FROM public.produtos
            WHERE id = v_product_id AND ativo = true
            FOR NO KEY UPDATE;
        END IF;

        IF v_db_price IS NULL THEN RAISE EXCEPTION 'Produto não encontrado ou inativo.'; END IF;
        IF v_db_stock < v_quantity THEN RAISE EXCEPTION 'Estoque insuficiente para: %', v_product_name; END IF;

        v_calculated_subtotal := v_calculated_subtotal + (v_db_price * v_quantity);
    END LOOP;

    -- 3. Calculate Shipping
    IF v_calculated_subtotal >= COALESCE(v_store_config.free_shipping_min, 999999) THEN
        v_shipping_validated := 0;
    ELSE
        v_shipping_validated := COALESCE(v_store_config.shipping_fee, 0);
    END IF;

    -- 4. Validate Coupon
    IF p_coupon_code IS NOT NULL AND p_coupon_code != '' THEN
        SELECT id, value INTO v_coupon_id, v_discount_amount
        FROM public.coupons
        WHERE code = p_coupon_code 
          AND active = true 
          AND (valid_until IS NULL OR valid_until > now())
          AND (usage_limit IS NULL OR usage_count < usage_limit)
          AND (min_purchase IS NULL OR v_calculated_subtotal >= min_purchase)
          FOR SHARE;

        IF v_coupon_id IS NULL THEN
            RAISE EXCEPTION 'Cupom inválido ou expirado.';
        END IF;
    END IF;

    -- 5. Final Calculation
    v_calculated_total := GREATEST(0, v_calculated_subtotal + v_shipping_validated - v_discount_amount);

    -- 6. Insert Order
    INSERT INTO public.marketplace_orders (
        user_id, total_amount, shipping_cost, payment_method, address_id, 
        coupon_id, status, observation, customer_name, customer_data,
        subtotal, discount
    ) VALUES (
        v_user_id, v_calculated_total, v_shipping_validated, p_payment_method, p_address_id, 
        v_coupon_id, 'pending', p_observation, p_customer_name,
        jsonb_build_object('whatsapp', p_customer_phone, 'address_id', p_address_id),
        v_calculated_subtotal, v_discount_amount
    ) RETURNING id INTO v_order_id;

    -- 7. Process Items
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_product_id := (v_item->>'product_id')::uuid;
        v_variant_id := (v_item->>'variant_id')::uuid;
        v_quantity := (v_item->>'quantity')::integer;

        IF v_variant_id IS NOT NULL THEN
            UPDATE public.product_variants SET stock_increment = stock_increment - v_quantity WHERE id = v_variant_id;
            SELECT COALESCE(v.price_override, p.preco_venda), p.nome INTO v_db_price, v_product_name FROM public.produtos p JOIN public.product_variants v ON v.product_id = p.id WHERE v.id = v_variant_id;
        ELSE
            UPDATE public.produtos SET estoque = estoque - v_quantity WHERE id = v_product_id;
            SELECT preco_venda, nome INTO v_db_price, v_product_name FROM public.produtos WHERE id = v_product_id;
        END IF;

        INSERT INTO public.marketplace_order_items (
            order_id, product_id, variant_id, quantity, price, product_name
        ) VALUES (
            v_order_id, v_product_id, v_variant_id, v_quantity, v_db_price, v_product_name
        );
    END LOOP;

    -- 8. Finalize
    IF v_coupon_id IS NOT NULL THEN
        UPDATE public.coupons SET usage_count = usage_count + 1 WHERE id = v_coupon_id;
    END IF;

    RETURN v_order_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_marketplace_order_v22(p_items jsonb, p_total_amount numeric, p_shipping_cost numeric, p_payment_method text, p_address_id uuid, p_coupon_code text DEFAULT NULL::text, p_customer_name text DEFAULT NULL::text, p_customer_phone text DEFAULT NULL::text, p_observation text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_id uuid := auth.uid();
    v_order_id uuid;
    v_item jsonb;
    v_product_id uuid;
    v_variant_id uuid;
    v_quantity integer;
    v_item_name text;
    v_item_image_url text;

    v_db_price numeric;
    v_db_stock integer;
    v_calculated_subtotal numeric := 0;
    v_calculated_total numeric := 0;
    v_discount_amount numeric := 0;
    v_shipping_validated numeric := 0;
    v_coupon_id uuid;

    v_store_config RECORD;
    v_rows_affected integer;
BEGIN
    -- [SECURITY] Auth check
    IF v_user_id IS NULL THEN RAISE EXCEPTION 'Não autenticado.'; END IF;

    -- [SECURITY] Address BOLA check
    IF p_address_id IS NOT NULL THEN
        IF NOT EXISTS (SELECT 1 FROM user_addresses WHERE id = p_address_id AND user_id = v_user_id) THEN
            RAISE EXCEPTION 'Endereço inválido.';
        END IF;
    END IF;

    -- 1. Carregar Configurações da Loja
    SELECT * INTO v_store_config FROM public.store_config WHERE id = 1;

    -- 2. Validar Itens e Calcular Subtotal (Pre-Check)
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_product_id := (v_item->>'product_id')::uuid;
        v_variant_id := (v_item->>'variant_id')::uuid;
        v_quantity := (v_item->>'quantity')::integer;

        IF v_quantity <= 0 THEN RAISE EXCEPTION 'Quantidade inválida.'; END IF;

        IF v_variant_id IS NOT NULL THEN
            SELECT COALESCE(v.price_override, p.preco_venda), v.stock_increment, p.nome
            INTO v_db_price, v_db_stock, v_item_name
            FROM public.produtos p
            JOIN public.product_variants v ON v.product_id = p.id
            WHERE v.id = v_variant_id AND p.id = v_product_id
              AND v.active = true AND p.ativo = true
            FOR NO KEY UPDATE OF v;
        ELSE
            SELECT preco_venda, estoque, nome
            INTO v_db_price, v_db_stock, v_item_name
            FROM public.produtos
            WHERE id = v_product_id AND ativo = true
            FOR NO KEY UPDATE;
        END IF;

        IF v_db_price IS NULL THEN RAISE EXCEPTION 'Produto não encontrado.'; END IF;
        IF v_db_stock < v_quantity THEN 
            RAISE EXCEPTION 'Estoque insuficiente para %: Disponível %, Necessário %', v_item_name, v_db_stock, v_quantity; 
        END IF;

        v_calculated_subtotal := v_calculated_subtotal + (v_db_price * v_quantity);
    END LOOP;

    -- 3. Calcular Frete
    IF v_calculated_subtotal >= COALESCE(v_store_config.free_shipping_min, 999999) THEN
        v_shipping_validated := 0;
    ELSE
        v_shipping_validated := COALESCE(v_store_config.shipping_fee, 0);
    END IF;

    -- 4. Validar Cupom (Share lock para evitar esgotamento simultâneo)
    IF p_coupon_code IS NOT NULL AND p_coupon_code != '' THEN
        SELECT id, value INTO v_coupon_id, v_discount_amount
        FROM public.coupons
        WHERE code = p_coupon_code 
          AND active = true 
          AND (valid_until IS NULL OR valid_until > now())
          AND (usage_limit IS NULL OR usage_count < usage_limit)
          AND (min_purchase IS NULL OR v_calculated_subtotal >= min_purchase)
          FOR SHARE;

        IF v_coupon_id IS NULL THEN
            RAISE EXCEPTION 'Cupom inválido ou expirado.';
        END IF;
    END IF;

    -- 5. Total Final Re-calculado
    v_calculated_total := GREATEST(0, v_calculated_subtotal + v_shipping_validated - v_discount_amount);

    -- 6. Validação Cruzada de Preço (Segurança)
    IF ABS(v_calculated_total - p_total_amount) > 0.05 THEN
        RAISE EXCEPTION 'Manipulação de preço detectada. Calculado: %, Fornecido: %', v_calculated_total, p_total_amount;
    END IF;

    -- 7. Criar Registro do Pedido
    INSERT INTO public.marketplace_orders (
        user_id, total, shipping, payment_method, address_id, 
        coupon_id, status, notes, customer_name, customer_data,
        subtotal, discount, coupon_code
    ) VALUES (
        v_user_id, v_calculated_total, v_shipping_validated, p_payment_method, p_address_id, 
        v_coupon_id, 'pending', p_observation, p_customer_name,
        jsonb_build_object('whatsapp', p_customer_phone, 'address_id', p_address_id, 'ref', 'atomic_v22'),
        v_calculated_subtotal, v_discount_amount, p_coupon_code
    ) RETURNING id INTO v_order_id;

    -- 8. Dedução de Estoque ATÔMICA e Inserir Itens
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_product_id := (v_item->>'product_id')::uuid;
        v_variant_id := (v_item->>'variant_id')::uuid;
        v_quantity := (v_item->>'quantity')::integer;

        -- Padrão de Atualização Atômica (Previne Race Condition)
        IF v_variant_id IS NOT NULL THEN
            UPDATE public.product_variants 
            SET stock_increment = stock_increment - v_quantity 
            WHERE id = v_variant_id AND stock_increment >= v_quantity;

            GET DIAGNOSTICS v_rows_affected = ROW_COUNT;

            SELECT COALESCE(v.price_override, p.preco_venda), p.nome, p.imagem_url
            INTO v_db_price, v_item_name, v_item_image_url
            FROM public.produtos p JOIN public.product_variants v ON v.product_id = p.id WHERE v.id = v_variant_id;
        ELSE
            UPDATE public.produtos 
            SET estoque = estoque - v_quantity 
            WHERE id = v_product_id AND estoque >= v_quantity;

            GET DIAGNOSTICS v_rows_affected = ROW_COUNT;

            SELECT preco_venda, nome, imagem_url 
            INTO v_db_price, v_item_name, v_item_image_url 
            FROM public.produtos WHERE id = v_product_id;
        END IF;

        -- Se nenhuma linha foi afetada, o estoque mudou entre o check e o update final
        IF v_rows_affected = 0 THEN
            RAISE EXCEPTION 'Race Condition detectada: O item % esgotou. Tente novamente.', v_item_name;
        END IF;

        INSERT INTO public.marketplace_order_items (
            order_id, product_id, variant_id, quantity, price, product_name, image_url
        ) VALUES (
            v_order_id, v_product_id, v_variant_id, v_quantity, v_db_price, v_item_name, v_item_image_url
        );
    END LOOP;

    -- 9. Incrementar uso do cupom
    IF v_coupon_id IS NOT NULL THEN
        UPDATE public.coupons SET usage_count = usage_count + 1 WHERE id = v_coupon_id;
    END IF;

    RETURN v_order_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.ensure_role_protection()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    -- Prevent role changes unless the executor is an admin
    IF (OLD.role <> NEW.role) AND NOT EXISTS (
        SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'
    ) THEN
        NEW.role = OLD.role;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.generate_order_otp_v1(p_email text, p_whatsapp text, p_order_fragment text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_otp TEXT;
    v_exists BOOLEAN;
BEGIN
    -- Validate if a matching order exists
    -- p_order_fragment should match the END of an order ID for this email/whatsapp
    -- Using ILIKE for case-insensitive and matching the end
    SELECT EXISTS (
        SELECT 1 FROM public.orders 
        WHERE (customer->>'email' = p_email OR customer->>'whatsapp' = p_whatsapp)
        AND id::text ILIKE '%' || p_order_fragment
    ) INTO v_exists;

    IF NOT v_exists THEN
        RAISE EXCEPTION 'Dados do pedido não encontrados.';
    END IF;

    -- Generate a 6-digit OTP
    v_otp := LPAD(FLOOR(RANDOM() * 1000000)::TEXT, 6, '0');

    -- Insert into verifications table
    INSERT INTO public.otp_verifications (email, whatsapp, otp_code, expires_at)
    VALUES (p_email, p_whatsapp, v_otp, NOW() + INTERVAL '15 minutes');

    RETURN v_otp;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_admin_analytics_v2()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    result jsonb;
    -- Today stats
    today_revenue numeric;
    today_count bigint;
    today_pending bigint;
    yesterday_revenue numeric;
    yesterday_count bigint;
    today_rev_trend numeric;
    today_count_trend numeric;

    -- month stats
    month_revenue numeric;
    month_count bigint;
    prev_month_revenue numeric;
    prev_month_count bigint;
    month_rev_trend numeric;
    month_count_trend numeric;

    -- executive stats (30 days)
    rev_30d numeric;
    count_30d bigint;
    prev_rev_30d numeric;
    prev_count_30d bigint;
    rev_30d_trend numeric;
    count_30d_trend numeric;

    -- avg ticket (30 days)
    avg_ticket_30d numeric;
    prev_avg_ticket_30d numeric;
    avg_ticket_trend numeric;

    -- active customers (30 days)
    active_customers_30d bigint;
    prev_active_customers_30d bigint;
    active_customers_trend numeric;

    -- history
    rev_history jsonb;
    top_prods jsonb;
BEGIN
    -- SECURITY CHECK
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Unauthorized';
    END IF;

    -- 1. Today vs Yesterday (Same period)
    -- Current day so far
    SELECT coalesce(sum(total), 0), count(*)
    INTO today_revenue, today_count
    FROM public.marketplace_orders
    WHERE created_at >= date_trunc('day', now())
    AND status NOT IN ('cancelled', 'returned');

    -- Yesterday same period (up to current hour/minute)
    SELECT coalesce(sum(total), 0), count(*)
    INTO yesterday_revenue, yesterday_count
    FROM public.marketplace_orders
    WHERE created_at >= date_trunc('day', now() - interval '1 day')
    AND created_at < now() - interval '1 day'
    AND status NOT IN ('cancelled', 'returned');

    -- Trends
    today_rev_trend := CASE WHEN yesterday_revenue > 0 THEN ((today_revenue - yesterday_revenue) / yesterday_revenue) * 100 ELSE (CASE WHEN today_revenue > 0 THEN 100 ELSE 0 END) END;
    today_count_trend := CASE WHEN yesterday_count > 0 THEN ((today_count::numeric - yesterday_count::numeric) / yesterday_count::numeric) * 100 ELSE (CASE WHEN today_count > 0 THEN 100 ELSE 0 END) END;

    -- Pending
    SELECT count(*) INTO today_pending
    FROM public.marketplace_orders
    WHERE status in ('new', 'processing');

    -- 2. month vs Previous Month
    SELECT coalesce(sum(total), 0), count(*)
    INTO month_revenue, month_count
    FROM public.marketplace_orders
    WHERE created_at >= date_trunc('month', now())
    AND status NOT IN ('cancelled', 'returned');

    SELECT coalesce(sum(total), 0), count(*)
    INTO prev_month_revenue, prev_month_count
    FROM public.marketplace_orders
    WHERE created_at >= date_trunc('month', now() - interval '1 month')
    AND created_at < date_trunc('month', now())
    AND status NOT IN ('cancelled', 'returned');

    month_rev_trend := CASE WHEN prev_month_revenue > 0 THEN ((month_revenue - prev_month_revenue) / prev_month_revenue) * 100 ELSE (CASE WHEN month_revenue > 0 THEN 100 ELSE 0 END) END;
    month_count_trend := CASE WHEN prev_month_count > 0 THEN ((month_count::numeric - prev_month_count::numeric) / prev_month_count::numeric) * 100 ELSE (CASE WHEN month_count > 0 THEN 100 ELSE 0 END) END;

    -- 3. Executive Metrics (Last 30 Days vs Previous 30 Days)
    -- 30d Revenue/Count
    SELECT coalesce(sum(total), 0), count(*)
    INTO rev_30d, count_30d
    FROM public.marketplace_orders
    WHERE created_at >= now() - interval '30 days'
    AND status NOT IN ('cancelled', 'returned');

    SELECT coalesce(sum(total), 0), count(*)
    INTO prev_rev_30d, prev_count_30d
    FROM public.marketplace_orders
    WHERE created_at >= now() - interval '60 days'
    AND created_at < now() - interval '30 days'
    AND status NOT IN ('cancelled', 'returned');

    rev_30d_trend := CASE WHEN prev_rev_30d > 0 THEN ((rev_30d - prev_rev_30d) / prev_rev_30d) * 100 ELSE (CASE WHEN rev_30d > 0 THEN 100 ELSE 0 END) END;
    count_30d_trend := CASE WHEN prev_count_30d > 0 THEN ((count_30d::numeric - prev_count_30d::numeric) / prev_count_30d::numeric) * 100 ELSE (CASE WHEN count_30d > 0 THEN 100 ELSE 0 END) END;

    -- Avg Ticket 30d
    avg_ticket_30d := CASE WHEN count_30d > 0 THEN rev_30d / count_30d ELSE 0 END;
    prev_avg_ticket_30d := CASE WHEN prev_count_30d > 0 THEN prev_rev_30d / prev_count_30d ELSE 0 END;
    avg_ticket_trend := CASE WHEN prev_avg_ticket_30d > 0 THEN ((avg_ticket_30d - prev_avg_ticket_30d) / prev_avg_ticket_30d) * 100 ELSE (CASE WHEN avg_ticket_30d > 0 THEN 100 ELSE 0 END) END;

    -- Active Core (Unique Users with at least 1 order in 30d)
    SELECT count(DISTINCT COALESCE(user_id::text, customer_data->>'email', customer_data->>'whatsapp'))
    INTO active_customers_30d
    FROM public.marketplace_orders
    WHERE created_at >= now() - interval '30 days'
    AND status NOT IN ('cancelled', 'returned');

    SELECT count(DISTINCT COALESCE(user_id::text, customer_data->>'email', customer_data->>'whatsapp'))
    INTO prev_active_customers_30d
    FROM public.marketplace_orders
    WHERE created_at >= now() - interval '60 days'
    AND created_at < now() - interval '30 days'
    AND status NOT IN ('cancelled', 'returned');

    active_customers_trend := CASE WHEN prev_active_customers_30d > 0 THEN ((active_customers_30d::numeric - prev_active_customers_30d::numeric) / prev_active_customers_30d::numeric) * 100 ELSE (CASE WHEN active_customers_30d > 0 THEN 100 ELSE 0 END) END;

    -- 4. Revenue & Orders History (Last 30 Days for charts)
    WITH days AS (
        SELECT generate_series(
            date_trunc('day', now()) - interval '29 days',
            date_trunc('day', now()),
            interval '1 day'
        )::date AS day
    )
    SELECT jsonb_agg(h)
    INTO rev_history
    FROM (
        SELECT 
            to_char(d.day, 'DD/MM') AS date,
            d.day::text AS full_date,
            coalesce(sum(o.total), 0) AS revenue,
            count(o.id) as orders,
            CASE WHEN count(o.id) > 0 THEN coalesce(sum(o.total), 0) / count(o.id) ELSE 0 END as avg_ticket
        FROM days d
        LEFT JOIN public.marketplace_orders o ON date_trunc('day', o.created_at)::date = d.day 
            AND o.status NOT IN ('cancelled', 'returned')
        GROUP BY d.day
        ORDER BY d.day
    ) h;

    -- 5. Top Products (30d)
    SELECT jsonb_agg(p)
    INTO top_prods
    FROM (
        SELECT 
            p.id as id,
            p.nome AS name,
            count(o.id) as quantity,
            sum(oi.price * oi.quantity) as total,
            max(p.imagem_url) as image
        FROM public.produtos p
        JOIN public.marketplace_order_items oi ON p.id = oi.product_id
        JOIN public.marketplace_orders o ON oi.order_id = o.id
        WHERE o.created_at >= now() - interval '30 days'
        AND o.status NOT IN ('cancelled', 'returned')
        GROUP BY p.id, p.nome
        ORDER BY quantity DESC
        LIMIT 5
    ) p;

    -- BUILD FINAL OBJECT
    result := jsonb_build_object(
        'today', jsonb_build_object(
            'revenue', today_revenue, 
            'count', today_count, 
            'pending', today_pending,
            'revenueTrend', round(today_rev_trend, 1),
            'countTrend', round(today_count_trend, 1)
        ),
        'month', jsonb_build_object(
            'revenue', month_revenue, 
            'count', month_count,
            'revenueTrend', round(month_rev_trend, 1),
            'countTrend', round(month_count_trend, 1)
        ),
        'executive', jsonb_build_object(
            'totalRevenue', rev_30d,
            'totalOrders', count_30d,
            'revenueTrend', round(rev_30d_trend, 1),
            'ordersTrend', round(count_30d_trend, 1),
            'avgTicket', round(avg_ticket_30d, 2),
            'avgTicketTrend', round(avg_ticket_trend, 1),
            'activeCustomers', active_customers_30d,
            'activeCustomersTrend', round(active_customers_trend, 1)
        ),
        'revenueHistory', rev_history,
        'topProducts', top_prods,
        'inventoryAlerts', (SELECT count(*) FROM public.produtos WHERE estoque <= estoque_minimo)
    );

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_admin_dashboard_stats()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_today_start TIMESTAMP := CURRENT_DATE;
    v_month_start TIMESTAMP := date_trunc('month', CURRENT_DATE);
    v_stats JSONB;
BEGIN
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Acesso negado';
    END IF;

    SELECT jsonb_build_object(
        'today', (
            SELECT jsonb_build_object(
                'count', COUNT(*),
                'revenue', COALESCE(SUM(total), 0),
                'pending', (SELECT COUNT(*) FROM public.marketplace_orders WHERE status IN ('new', 'processing'))
            )
            FROM public.marketplace_orders
            WHERE created_at >= v_today_start
            AND status NOT IN ('cancelled', 'returned')
        ),
        'month', (
            SELECT jsonb_build_object(
                'count', COUNT(*),
                'revenue', COALESCE(SUM(total), 0)
            )
            FROM public.marketplace_orders
            WHERE created_at >= v_month_start
            AND status NOT IN ('cancelled', 'returned')
        ),
        'average_ticket', (
            SELECT COALESCE(AVG(total), 0) 
            FROM public.marketplace_orders 
            WHERE status NOT IN ('cancelled', 'returned')
        ),
        'revenue_history', (
            SELECT jsonb_agg(d.day_data) FROM (
                SELECT jsonb_build_object(
                    'date', to_char(gs.day, 'DD/MM'),
                    'revenue', COALESCE(SUM(o.total), 0)
                ) as day_data
                FROM generate_series(CURRENT_DATE - INTERVAL '6 days', CURRENT_DATE, INTERVAL '1 day') AS gs(day)
                LEFT JOIN public.marketplace_orders o ON date_trunc('day', o.created_at) = gs.day 
                    AND o.status NOT IN ('cancelled', 'returned')
                GROUP BY gs.day
                ORDER BY gs.day ASC
            ) d
        )
    ) INTO v_stats;

    RETURN v_stats;
END;
$function$

