CREATE OR REPLACE FUNCTION public.get_orders_by_whatsapp_v3(p_phone_number text, p_customer_email text, p_order_fragment text)
 RETURNS SETOF marketplace_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_id UUID;
BEGIN
    IF LENGTH(p_order_fragment) < 6 THEN
        RAISE EXCEPTION 'Fragmento muito curto. Informe pelo menos 6 dígitos para sua segurança.';
    END IF;

    SELECT id INTO v_user_id 
    FROM auth.users 
    WHERE (phone = p_phone_number OR raw_user_meta_data->>'whatsapp' = p_phone_number) 
      AND email = p_customer_email;

    IF v_user_id IS NULL THEN RETURN; END IF;

    IF NOT EXISTS (
        SELECT 1 FROM public.marketplace_orders 
        WHERE user_id = v_user_id 
        AND (id::text LIKE '%' || p_order_fragment OR tracking_code LIKE '%' || p_order_fragment)
    ) THEN
        RETURN;
    END IF;

    RETURN QUERY 
    SELECT * FROM public.marketplace_orders 
    WHERE user_id = v_user_id
    ORDER BY created_at DESC;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_retention_analytics(p_days integer DEFAULT 90)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_total_customers int;
    v_repeat_customers int;
BEGIN
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Acesso negado';
    END IF;

    WITH customer_counts AS (
        SELECT 
            COALESCE(user_id::text, customer_data->>'whatsapp') as customer_id,
            COUNT(*) as order_count
        FROM marketplace_orders
        WHERE created_at >= NOW() - (p_days || ' days')::interval
        AND status NOT IN ('cancelled', 'returned')
        GROUP BY customer_id
    )
    SELECT 
        COUNT(*),
        COUNT(*) FILTER (WHERE order_count > 1)
    INTO v_total_customers, v_repeat_customers
    FROM customer_counts;

    IF v_total_customers = 0 THEN
        RETURN 0;
    END IF;

    RETURN (v_repeat_customers::numeric / v_total_customers::numeric) * 100;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_retention_rate()
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    total_customers bigint := 0;
    repeated_customers bigint := 0;
    retention_rate numeric := 0;
BEGIN
    IF NOT public.is_admin() THEN
        RAISE EXCEPTION 'Não autorizado.';
    END IF;

    SELECT count(DISTINCT user_id) INTO total_customers
    FROM public.marketplace_orders
    WHERE status NOT IN ('cancelled', 'returned');

    IF total_customers > 0 THEN
        WITH order_counts AS (
            SELECT count(*) AS purchase_count FROM public.marketplace_orders
            WHERE status NOT IN ('cancelled', 'returned') GROUP BY user_id
        )
        SELECT count(*) INTO repeated_customers FROM order_counts WHERE purchase_count > 1;
        retention_rate := (repeated_customers::numeric / total_customers::numeric) * 100.0;
    END IF;

    RETURN round(retention_rate, 1);
END;
$function$

